BEGIN;
CREATE TABLE IF NOT EXISTS schema_migrations (version varchar(64) PRIMARY KEY, description text NOT NULL, applied_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS users (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,email text UNIQUE NOT NULL,username text UNIQUE,account_number text UNIQUE,scope_id text,display_name text NOT NULL,password_hash text NOT NULL,role text NOT NULL CHECK (role IN ('ADMIN','EXECUTIVE','DISPATCHER','DRIVER','BILLING','QA','FACILITY','PATIENT')),active boolean NOT NULL DEFAULT true,failed_logins integer NOT NULL DEFAULT 0 CHECK (failed_logins >= 0),locked_until timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS sessions (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,token_digest text UNIQUE NOT NULL,user_id bigint NOT NULL REFERENCES users(id) ON DELETE CASCADE,expires_at timestamptz NOT NULL,ip_address text,user_agent text,created_at timestamptz NOT NULL DEFAULT now(),revoked_at timestamptz);
CREATE INDEX IF NOT EXISTS idx_sessions_digest ON sessions(token_digest);
CREATE INDEX IF NOT EXISTS idx_sessions_user_active ON sessions(user_id, expires_at) WHERE revoked_at IS NULL;
CREATE TABLE IF NOT EXISTS bookings (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,reference text UNIQUE NOT NULL,name text NOT NULL,phone text NOT NULL,email text,service text NOT NULL,pickup text NOT NULL,destination text NOT NULL,trip_date date NOT NULL,trip_time time NOT NULL,notes text,status text NOT NULL DEFAULT 'SUBMITTED',driver_name text,vehicle_unit text,facility_id text,driver_scope_id text,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_bookings_status_updated ON bookings(status, updated_at DESC);
CREATE INDEX IF NOT EXISTS idx_bookings_facility ON bookings(facility_id, trip_date, trip_time);
CREATE INDEX IF NOT EXISTS idx_bookings_driver ON bookings(driver_scope_id, trip_date, trip_time);
CREATE TABLE IF NOT EXISTS partnerships (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,reference text UNIQUE NOT NULL,organization text NOT NULL,type text NOT NULL,contact text NOT NULL,email text NOT NULL,phone text NOT NULL,needs text NOT NULL,status text NOT NULL DEFAULT 'RECEIVED',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS audit_log (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,entity_type text NOT NULL,entity_reference text NOT NULL,action text NOT NULL,detail text,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_audit_entity ON audit_log(entity_type, entity_reference, created_at DESC);
CREATE TABLE IF NOT EXISTS trip_status_history (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,booking_reference text NOT NULL REFERENCES bookings(reference) ON DELETE CASCADE,status text NOT NULL,status_label text NOT NULL,note text,actor text NOT NULL DEFAULT 'Nexus Operations',created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_trip_status_reference ON trip_status_history(booking_reference, created_at);
CREATE TABLE IF NOT EXISTS trip_messages (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,booking_reference text NOT NULL REFERENCES bookings(reference) ON DELETE CASCADE,sender_role text NOT NULL,sender_name text NOT NULL,message text NOT NULL,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_trip_messages_reference ON trip_messages(booking_reference, created_at);
CREATE TABLE IF NOT EXISTS tracking_links (id bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,token text UNIQUE NOT NULL,booking_reference text NOT NULL REFERENCES bookings(reference) ON DELETE CASCADE,expires_at timestamptz NOT NULL,revoked boolean NOT NULL DEFAULT false,created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_tracking_active ON tracking_links(token, expires_at) WHERE revoked = false;
INSERT INTO schema_migrations(version, description) VALUES ('040.001', 'Initial production PostgreSQL schema') ON CONFLICT (version) DO NOTHING;
COMMIT;
